try {
  const CONFIG = {
    AIRTABLE_PAT: "REPLACE_WITH_AIRTABLE_PAT",
    AIRTABLE_BASE_ID: "REPLACE_WITH_AIRTABLE_BASE_ID",
    CODE_SAMUEL: "nerve",
    CODE_MATHILDE: "mathilde",
    CODE_AMIS_SAMUEL: "amis-samuel",
    CODE_AMIS_MATHILDE: "amis-mathilde",
  };

  const request = this.helpers.httpRequest.bind(this.helpers);
  const rawCode = String($json.body?.code || "").trim();
  const normalize = (value) => String(value || "").trim().toLowerCase();
  const inputCode = normalize(rawCode);

  const codes = {
    samuel: normalize(CONFIG.CODE_SAMUEL),
    mathilde: normalize(CONFIG.CODE_MATHILDE),
    amis_samuel: normalize(CONFIG.CODE_AMIS_SAMUEL),
    amis_mathilde: normalize(CONFIG.CODE_AMIS_MATHILDE),
  };

  const role = Object.entries(codes).find(([, code]) => code && code === inputCode)?.[0];
  if (!role) {
    return { json: { statusCode: 401, error: "Code invalide", code: "invalid_group_code" } };
  }

  const apiKey = CONFIG.AIRTABLE_PAT;
  const baseId = CONFIG.AIRTABLE_BASE_ID;
  if (!apiKey || !baseId || apiKey.includes("REPLACE_WITH") || baseId.includes("REPLACE_WITH")) {
    return { json: { statusCode: 500, error: "Airtable config missing in n8n code node", code: "airtable_config_missing" } };
  }

  const airtable = "https://api.airtable.com/v0/" + baseId;
  const formula = "LOWER({role}) = '" + role.toLowerCase().replace(/'/g, "\'") + "'";
  const searchUrl = airtable + "/Users?maxRecords=1&filterByFormula=" + encodeURIComponent(formula);

  let data;
  try {
    data = await request({
      method: "GET",
      url: searchUrl,
      headers: { Authorization: "Bearer " + apiKey },
      json: true,
    });
  } catch (error) {
    return { json: { statusCode: 500, error: "Airtable user lookup failed: " + (error?.message || String(error)), code: "airtable_users_failed" } };
  }

  const record = data.records?.[0];
  if (!record) {
    return { json: { statusCode: 401, error: "Aucun utilisateur pour ce groupe", code: "group_user_missing" } };
  }

  const sessionToken = "sess_" + Date.now().toString(36) + "_" + Math.random().toString(36).slice(2);
  const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString();

  try {
    await request({
      method: "PATCH",
      url: airtable + "/Users/" + record.id,
      headers: { Authorization: "Bearer " + apiKey },
      body: {
        fields: {
          session_token: sessionToken,
          session_expires_at: expiresAt,
        },
      },
      json: true,
    });
  } catch (error) {
    return { json: { statusCode: 500, error: "Airtable session update failed: " + (error?.message || String(error)), code: "airtable_session_failed" } };
  }

  return {
    json: {
      session_token: sessionToken,
      user: {
        id: record.fields.id || record.id,
        name: record.fields.name || role,
        role,
      },
    },
  };
} catch (error) {
  return {
    json: {
      statusCode: 500,
      error: error?.message || String(error),
      code: "auth_verify_unhandled_error",
    },
  };
}
